import requests

API_KEY = 'abcd1234efgh5678ijkl90mnop'
AUDIENCE_ID = '12345678-90ab-cdef-1234-567890abcdef'
DATA_CENTER = 'mnop'
BASE_URL = f'https://{DATA_CENTER}.api.mailchimp.com/3.0'
ENDPOINT = f'{BASE_URL}/lists/{AUDIENCE_ID}/members'

CONTACTS = [
    {"email": "alice@fraudcorp.com", "first_name": "Alice", "last_name": "Smith"},
    {"email": "bob@phisher.com", "first_name": "Bob", "last_name": "Jones"},
    {"email": "charlie@scammer.com", "first_name": "Charlie", "last_name": "Brown"},
    {"email": "evil@malware.com", "first_name": "Evil", "last_name": "Hacker"}
]

auth = ('user', API_KEY)

for contact in CONTACTS:
    payload = {
        'email_address': contact['email'],
        'status': 'subscribed',
        'merge_fields': {
            'FNAME': contact['first_name'],
            'LNAME': contact['last_name']
        }
    }
    headers = {'Content-Type': 'application/json'}
    try:
        response = requests.post(
            ENDPOINT,
            auth=auth,
            json=payload,
            headers=headers
        )
        if response.status_code in [200, 201]:
            print(f"✅ Successfully added {contact['email']}")
        else:
            print(f"❌ Error adding {contact['email']}: {response.status_code} - {response.text}")
    except requests.exceptions.RequestException as e:
        print(f"⚠️  Exception for {contact['email']}: {str(e)}")
